function validateUserProfile(data) {
  if (typeof data !== "object" || data === null) return false;
  if (!Array.isArray(data.addresses)) return false;
  if (!Array.isArray(data.orders)) return false;
  if (typeof data.preferences !== "object" || data.preferences === null) return false;
  return true;
}

if (validateUserProfile(userProfile)) {
  console.log("User profile is valid!");
} else {
  console.log("Invalid user profile data.");
}

function LogCreation(constructor: Function) {
  const original = constructor;

  function construct(constructor: any, args: any[]) {
    console.log(`Creating instance of ${constructor.name}`);
    return new constructor(...args);
  }

  const newConstructor: any = function (...args: any[]) {
    return construct(original, args);
  };

  newConstructor.prototype = original.prototype;
  return newConstructor;
}

@LogCreation
class Person {
  constructor(public name: string) {}
}

const p = new Person('Alice');

function Timer(
  target: any,
  propertyKey: string,
  descriptor: PropertyDescriptor
) {
  const originalMethod = descriptor.value;

  descriptor.value = function (...args: any[]) {
    console.time(`${propertyKey} execution time`);
    const result = originalMethod.apply(this, args);
    console.timeEnd(`${propertyKey} execution time`);
    return result;
  };

  return descriptor;
}

class Calculator {
  @Timer
  fibonacci(n: number): number {
    if (n <= 1) return n;
    return this.fibonacci(n - 1) + this.fibonacci(n - 2);
  }
}

const calc = new Calculator();
console.log(calc.fibonacci(10));

function MinLength(length: number) {
  return function (target: any, propertyKey: string) {
    let value: string = '';

    const getter = () => value;
    const setter = (newVal: string) => {
      if (newVal.length < length) {
        throw new Error(
          `${propertyKey} should be at least ${length} characters long.`
        );
      }
      value = newVal;
    };

    Object.defineProperty(target, propertyKey, {
      get: getter,
      set: setter,
      enumerable: true,
      configurable: true,
    });
  };
}

class User {
  @MinLength(5)
  username: string;

  constructor(username: string) {
    this.username = username;
  }
}

const user = new User('admin'); // Works fine
// const badUser = new User('abc'); // Throws error

function LogParameter(
  target: any,
  propertyKey: string | symbol,
  parameterIndex: number
) {
  console.log(
    `Parameter at position ${parameterIndex} in method ${String(propertyKey)} is decorated.`
  );
}

class Greeter {
  greet(@LogParameter message: string) {
    console.log(message);
  }
}

const greeter = new Greeter();
greeter.greet('Hello!');

