}

function printUser(user: {name: string, age: number}) {
  console.log(user.name, user.age);
}

printUser({name: "Alice", age: 25, agge: 30});
// No error even though 'agge' is misspelled

type User = {
  name: string;
  age: number;
};

function printUser(user: User) {
  console.log(user.name, user.age);
}

// Now TypeScript will give an error if extra properties exist
printUser({name: "Alice", age: 25, agge: 30}); // Error: Object literal may only specify known properties

